# Try to find closest symbols for the unresolved SGen worker addresses
DBGFILE="/tmp/symbols/libmonosgen-2.0.dbg"
echo "=== Looking up nearby symbols for SGen worker frames ==="
aarch64-linux-gnu-nm -C "$DBGFILE" 2>/dev/null | awk '$1 != "" {addr=strtonum("0x"$1); print addr, $0}' | sort -n | awk '
BEGIN { targets[1]=0x2f4b20; targets[2]=0x2f4c84; ntargets=2 }
{
  addr = $1
  for (i=1; i<=ntargets; i++) {
    if (addr <= targets[i]) { prev[i] = $0 }
    if (addr > targets[i] && !printed[i]) {
      printf "Target 0x%x:\n  Before: %s\n  After:  %s\n\n", targets[i], prev[i], $0
      printed[i] = 1
    }
  }
}' 2>/dev/null | head -20

# Also try using objdump to disassemble around those addresses
echo "=== Disassembly context for 0x2f4b20 ==="
aarch64-linux-gnu-objdump -d --start-address=0x2f4b00 --stop-address=0x2f4b30 "$DBGFILE" 2>/dev/null | tail -10

