arguments.command:
# These addresses might be in BSS/data sections used as code pointers for the interpreter dispatch.
# Let me check what section they're in
DBGFILE="/tmp/symbols/libmonosgen-2.0.dbg"

# Check section mapping
readelf -S "$DBGFILE" | grep -E '^\s+\[' | awk '{
  if (NF > 5) {
    name=$2; addr=$4; off=$5; size=$6
    start=strtonum("0x"addr)
    sz=strtonum("0x"size)
    end=start+sz
    if (start <= 0x2f4b20 && 0x2f4b20 < end) printf "0x2f4b20 in section %s (0x%x - 0x%x)\n", name, start, end
    if (start <= 0x2f4c84 && 0x2f4c84 < end) printf "0x2f4c84 in section %s (0x%x - 0x%x)\n", name, start, end
  }
}'

# Alternatively, just find the closest T symbols before these addresses  
echo ""
echo "=== Closest function symbols before 0x2f4b20 ==="
aarch64-linux-gnu-nm -C "$DBGFILE" 2>/dev/null | grep ' [tT] ' | awk '{
  addr = strtonum("0x"$1)
  if (addr <= 0x2f4b20) { last = $0; lastaddr = addr }
}
END { printf "  %s (offset +0x%x)\n", last, 0x2f4b20 - lastaddr }'

echo "=== Closest function symbols before 0x2f4c84 ==="
