{"command": "# These addresses are in .data.rel.ro (0x2f3810-0x2f6a18), not .text
# They're function pointer table entries, not code. Let me find the nearest data symbols.
DBGFILE="/tmp/symbols/libmonosgen-2.0.dbg"

echo "=== All symbols near 0x2f4b20 and 0x2f4c84 ==="
aarch64-linux-gnu-nm -C "$DBGFILE" 2>/dev/null | awk '{
  addr = strtonum("0x"$1)
  if (addr >= 0x2f4000 && addr <= 0x2f5000) print $0
}' | head -20

echo ""
echo "=== Dynamic symbols near these addresses ==="
aarch64-linux-gnu-nm -C -D /tmp/symbols/libmonosgen-2.0.so 2>/dev/null | awk '{
  addr = strtonum("0x"$1)
  if (addr >= 0x2f4000 && addr <= 0x2f5000) print $0
}' | head -20", "description": "Identify data symbols at SGen addresses", "initial_wait": 30}

